mapper.update:
UPDATE TBL_GUESTBOOK
SET GUESTBOOK_CONTENT = #{guestbookContent}
WHERE ID = #{id}
AND WRITER_MEMBER_ID = #{writerMemberId}

mapper.delete:
DELETE FROM TBL_GUESTBOOK
WHERE ID = #{id}
AND (WRITER_MEMBER_ID = #{writerMemberId}
OR OWNER_MEMBER_ID = #{ownerMemberId})

DELETE FROM TBL_GUESTBOOK_REREPLY_LIKE
WHERE GUESTBOOK_REREPLY_ID IN (
    SELECT RR.ID FROM TBL_GUESTBOOK_REREPLY RR
    JOIN TBL_GUESTBOOK_REPLY R ON RR.GUESTBOOK_REPLY_ID = R.ID
    WHERE R.GUESTBOOK_ID = #{guestbookId}
)

DELETE FROM TBL_GUESTBOOK_REREPLY
WHERE GUESTBOOK_REPLY_ID IN (
    SELECT ID FROM TBL_GUESTBOOK_REPLY
    WHERE GUESTBOOK_ID = #{guestbookId}
)

DELETE FROM TBL_GUESTBOOK_REPLY_LIKE
WHERE GUESTBOOK_REPLY_ID IN (
    SELECT ID FROM TBL_GUESTBOOK_REPLY
    WHERE GUESTBOOK_ID = #{guestbookId}
)
